# Sound generation functions
def generate_sound(frequency, duration_ms, volume=0.5, wave_type='sine'):
    sample_rate = 44100
    frames = int(sample_rate * duration_ms / 1000)
    t = np.linspace(0, duration_ms / 1000, frames, False)

    if wave_type == 'sine':
        wave = np.sin(2 * np.pi * frequency * t)
    elif wave_type == 'square':
        wave = np.sign(np.sin(2 * np.pi * frequency * t))
    elif wave_type == 'sawtooth':
        wave = 2 * (t * frequency - np.floor(t * frequency + 0.5))

    # Apply envelope
    envelope = np.ones(frames)
    attack = min(int(frames * 0.1), 100)
    release = min(int(frames * 0.2), 200)
    if attack > 0:
        envelope[:attack] = np.linspace(0, 1, attack)
    if release > 0:
        envelope[-release:] = np.linspace(1, 0, release)

    wave = wave * envelope * volume * 32767
    wave = wave.astype(np.int16)
    stereo = np.column_stack([wave, wave])
    sound = pygame.sndarray.make_sound(stereo)
    return sound


def generate_waka_sound():
    sample_rate = 44100
    duration_ms = 100
    frames = int(sample_rate * duration_ms / 1000)
