def generate_start_sound():
    sample_rate = 44100
    notes = [261, 329, 392, 523, 392, 523]
    durations = [150, 150, 150, 300, 150, 400]

    all_waves = []
    for freq, dur in zip(notes, durations):
        frames = int(sample_rate * dur / 1000)
        t = np.linspace(0, dur / 1000, frames, False)
        wave = np.sin(2 * np.pi * freq * t) * 0.5
        wave += np.sin(2 * np.pi * freq * 2 * t) * 0.2
        envelope = np.ones(frames)
        release = int(frames * 0.2)
        if release > 0:
            envelope[-release:] = np.linspace(1, 0, release)
        wave = wave * envelope
        all_waves.append(wave)

    combined = np.concatenate(all_waves)
    combined = (combined * 0.6 * 32767).astype(np.int16)
    stereo = np.column_stack([combined, combined])
    return pygame.sndarray.make_sound(stereo)


