class Particle:
    def __init__(self, x, y, color):
        self.x = x
        self.y = y
        self.color = color
        self.vx = random.uniform(-3, 3)
        self.vy = random.uniform(-3, 3)
        self.life = 1.0
        self.size = random.randint(2, 6)

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += 0.1
        self.life -= 0.05
        return self.life > 0

    def draw(self, surface):
        alpha = int(self.life * 255)
        color = (*self.color[:3], alpha)
        size = max(1, int(self.size * self.life))
        pygame.draw.circle(surface, self.color[:3], (int(self.x), int(self.y)), size)


class Ghost:
    def __init__(self, x, y, color, name):
        self.start_x = x
        self.start_y = y
        self.x = x
        self.y = y
        self.color = color
        self.name = name
        self.direction = random.choice([(0, -1), (0, 1), (-1, 0), (1, 0)])
        self.scared = False
        self.scared_timer = 0
        self.speed = 0.08
        self.pixel_x = x * CELL_SIZE + CELL_SIZE // 2
        self.pixel_y = y * CELL_SIZE + CELL_SIZE // 2
        self.target_x = self.pixel_x
        self.target_y = self.pixel_y
        self.moving = False
        self.blink = False
        self.blink_timer = 0
        self.eaten = False
        self.eyes_only = False
        self.anim_frame = 0
        self.anim_timer = 0

    def reset(self):
        self.x = self.start_x
        self.y = self.start_y
        self.pixel_x = self.x * CELL_SIZE + CELL_SIZE // 2
        self.pixel_y = self.y * CELL_SIZE + CELL_SIZE // 2
        self.target_x = self.pixel_x
        self.target_y = self.pixel_y
        self.scared = False
        self.scared_timer = 0
        self.eaten = False
        self.eyes_only = False
        self.direction = random.choice([(0, -1), (0, 1), (-1, 0), (1, 0)])

    def get_scared(self):
        self.scared = True
        self.scared_timer = 300
        self.eaten = False
        self.eyes_only = False

    def update(self, maze, pacman_x, pacman_y):
        self.anim_timer += 1
        if self.anim_timer > 10:
            self.anim_frame = 1 - self.anim_frame
            self.anim_timer = 0

        if self.scared:
            self.scared_timer -= 1
            self.blink = self.scared_timer < 100
            if self.scared_timer <= 0:
                self.scared = False
                self.blink = False

        if not self.moving:
            possible = []
            for dx, dy in [(0, -1), (0, 1), (-1, 0), (1, 0)]:
                nx, ny = self.x + dx, self.y + dy
                if 0 <= nx < COLS and 0 <= ny < ROWS:
                    cell = maze[ny][nx]
                    if cell != 1:
                        if not (dx == -self.direction[0] and dy == -self.direction[1]):
                            possible.append((dx, dy))

            if not possible:
                possible = [(dx, dy) for dx, dy in [(0, -1), (0, 1), (-1, 0), (1, 0)]
                            if 0 <= self.x + dx < COLS and 0 <= self.y + dy < ROWS
                            and maze[self.y + dy][self.x + dx] != 1]

            if possible:
                if self.scared:
                    self.direction = random.choice(possible)
                elif self.eyes_only:
                    # Return to ghost house
                    best = min(possible, key=lambda d:
                    abs(self.x + d[0] - 9) + abs(self.y + d[1] - 9))
                    self.direction = best
                else:
                    # Chase or scatter
                    if random.random() < 0.7:
                        best = min(possible, key=lambda d:
                        abs(self.x + d[0] - pacman_x) + abs(self.y + d[1] - pacman_y))
                        self.direction = best
                    else:
                        self.direction = random.choice(possible)

                nx, ny = self.x + self.direction[0], self.y + self.direction[1]
                if 0 <= nx < COLS and 0 <= ny < ROWS and maze[ny][nx] != 1:
                    self.x = nx
                    self.y = ny
                    self.target_x = nx * CELL_SIZE + CELL_SIZE // 2
                    self.target_y = ny * CELL_SIZE + CELL_SIZE // 2
                    self.moving = True
        else:
            speed = 3 if self.eyes_only else 2
            dx = self.target_x - self.pixel_x
            dy = self.target_y - self.pixel_y
            dist = math.sqrt(dx * dx + dy * dy)
            if dist < speed:
                self.pixel_x = self.target_x
                self.pixel_y = self.target_y
                self.moving = False
                if self.eyes_only and self.x == 9 and self.y == 9:
                    self.eyes_only = False
                    self.eaten = False
                    self.scared = False
            else:
                self.pixel_x += int(dx / dist * speed)
                self.pixel_y += int(dy / dist * speed)

    def draw(self, surface, offset_x, offset_y):
        px = self.pixel_x + offset_x
        py = self.pixel_y + offset_y
        r = CELL_SIZE // 2 - 2

        if self.eyes_only:
            # Draw eyes only (returning to base)
            eye_color = WHITE
            pupil_color = BLUE
            for ex, ey in [(-5, -3), (5, -3)]:
                pygame.draw.circle(surface, eye_color, (px + ex, py + ey), 4)
                pygame.draw.circle(surface, pupil_color, (px + ex + 1, py + ey + 1), 2)
            return

        if self.scared:
            if self.blink and self.anim_frame == 0:
                color = SCARED_WHITE
            else:
                color = SCARED_BLUE
        else:
            color = self.color

        # Ghost body
        body_rect = pygame.Rect(px - r, py - r, r * 2, r * 2)
        pygame.draw.circle(surface, color, (px, py - 2), r)
        pygame.draw.rect(surface, color, (px - r, py - 2, r * 2, r))

        # Wavy bottom
        wave_points = []
        num_waves = 3
        wave_width = r * 2 / num_waves
        for i in range(num_waves * 2 + 1):
            wx = px - r + i * wave_width / 2
            if i % 2 == self.anim_frame:
                wy = py + r - 2
            else:
                wy = py + r - 8
            wave_points.append((wx, wy))

        if len(wave_points) >= 3:
            bottom_points = [(px - r, py + r)] + wave_points + [(px + r, py + r)]
            pygame.draw.polygon(surface, color, bottom_points)

        # Eyes
        if not self.scared:
            for ex, ey in [(-5, -4), (5, -4)]:
                pygame.draw.circle(surface, WHITE, (px + ex, py + ey), 4)
                # Pupil direction
                dx, dy = self.direction
                pygame.draw.circle(surface, DARK_BLUE, (px + ex + dx * 2, py + ey + dy * 2), 2)
        else:
            # Scared face
            pygame.draw.line(surface, WHITE, (px - 5, py - 2), (px - 3, py), 2)
            pygame.draw.line(surface, WHITE, (px - 3, py), (px - 1, py - 2), 2)
            pygame.draw.line(surface, WHITE, (px - 1, py - 2), (px + 1, py), 2)
            pygame.draw.line(surface, WHITE, (px + 1, py), (px + 3, py - 2), 2)
            pygame.draw.line(surface, WHITE, (px + 3, py - 2), (px + 5, py), 2)
            pygame.draw.circle(surface, WHITE, (px - 4, py - 5), 2)
            pygame.draw.circle(surface, WHITE, (px + 4, py - 5), 2)


class PacMan:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        self.pixel_x = x * CELL_SIZE + CELL_SIZE // 2
        self.pixel_y = y * CELL_SIZE + CELL_SIZE // 2
        self.target_x = self.pixel_x
        self.target_y = self.pixel_y
        self.direction = (1, 0)
        self.next_direction = (1, 0)
        self.moving = False
        self.mouth_angle = 45
        self.mouth_dir = -1
        self.alive = True
        self.death_anim = 0
        self.death_playing = False

    def reset(self):
        self.x = 9
        self.y = 16
        self.pixel_x = self.x * CELL_SIZE + CELL_SIZE // 2
        self.pixel_y = self.y * CELL_SIZE + CELL_SIZE // 2
        self.target_x = self.pixel_x
        self.target_y = self.pixel_y
        self.direction = (1, 0)
        self.next_direction = (1, 0)
        self.moving = False
        self.alive = True
        self.death_anim = 0
        self.death_playing = False

    def update(self, maze):
        if not self.alive:
            return

        # Animate mouth
        self.mouth_angle += self.mouth_dir * 4
        if self.mouth_angle <= 5:
            self.mouth_dir = 1
        elif self.mouth_angle >= 45:
            self.mouth_dir = -1

        if not self.moving:
            # Try next direction first
            for d in [self.next_direction, self.direction]:
                nx, ny = self.x + d[0], self.y + d[1]
                # Wrap around
                nx = nx % COLS
                ny = ny % ROWS
                if maze[ny][nx] != 1:
                    self.direction = d
                    self.x = nx
                    self.y = ny
                    self.target_x = nx * CELL_SIZE + CELL_SIZE // 2
                    self.target_y = ny * CELL_SIZE + CELL_SIZE // 2
                    self.moving = True
                    break
        else:
            speed = 3
            dx = self.target_x - self.pixel_x
            dy = self.target_y - self.pixel_y
            dist = math.sqrt(dx * dx + dy * dy)
            if dist < speed:
                self.pixel_x = self.target_x
                self.pixel_y = self.target_y
                self.moving = False
            else:
                self.pixel_x += int(dx / dist * speed)
                self.pixel_y += int(dy / dist * speed)

    def draw(self, surface, offset_x, offset_y):
        px = self.pixel_x + offset_x
        py = self.pixel_y + offset_y
        r = CELL_SIZE // 2 - 2

        if not self.alive:
            # Death animation
            angle = min(180, self.death_anim * 6)
            if angle < 180:
                start_angle = math.radians(angle / 2)
                end_angle = math.radians(360 - angle / 2)
                points = [(px, py)]
                for a in range(int(math.degrees(start_angle)), int(math.degrees(end_angle)) + 1, 5):
                    rad = math.radians(a)
                    points.append((px + r * math.cos(rad), py - r * math.sin(rad)))
                if len(points) > 2:
                    pygame.draw.polygon(surface, YELLOW, points)
            return

        # Calculate rotation angle based on direction
        dx, dy = self.direction
        if dx == 1:
            angle = 0
        elif dx == -1:
            angle = 180
        elif dy == -1:
            angle = 90
        else:
            angle = 270

        # Draw pacman
        mouth = self.mouth_angle
        start_angle = math.radians(angle + mouth)
        end_angle = math.radians(angle + 360 - mouth)

        points = [(px, py)]
        steps = 36
        for i in range(steps + 1):
            a = start_angle + (end_angle - start_angle) * i / steps
            points.append((px + r * math.cos(a), py - r * math.sin(a)))

        if len(points) > 2:
            pygame.draw.polygon(surface, YELLOW, points)

        # Eye
        eye_x = px + int(r * 0.3 * math.cos(math.radians(angle + 60)))
        eye_y = py - int(r * 0.3 * math.sin(math.radians(angle + 60)))
        pygame.draw.circle(surface, BLACK, (eye_x, eye_y), 2)


class Game:
    def __init__(self):
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("PAC-MAN")
        self.clock = pygame.time.Clock()

        # Load sounds
        print("Generating sounds...")
        self.waka_sound = generate_waka_sound()
        self.eat_ghost_sound = generate_eat_ghost_sound()
        self.death_sound = generate_death_sound()
        self.power_sound = generate_power_pellet_sound()
        self.start_sound = generate_start_sound()
        print("Sounds generated!")

        # Fonts
        self.font_large = pygame.font.Font(None, 72)
        self.font_medium = pygame.font.Font(None, 48)
        self.font_small = pygame.font.Font(None, 32)
        self.font_tiny = pygame.font.Font(None, 24)

        self.state = 'start'
        self.score = 0
        self.high_score = 0
        self.lives = 3
        self.level = 1
        self.particles = []
        self.score_popups = []
        self.flash_timer = 0
        self.flash_on = True

        self.init_game()

        # Background stars
        self.stars = [(random.randint(0, SCREEN_WIDTH), random.randint(0, SCREEN_HEIGHT),
                       random.randint(1, 3)) for _ in range(50)]

    def init_game(self):
        self.maze = [row[:] for row in MAZE]
        self.total_pellets = sum(1 for row in self.maze for cell in row if cell in [0, 3])
        self.pellets_eaten = 0

        self.pacman = PacMan(9, 16)

        ghost_data = [
            (9, 9, RED, 'Blinky'),
            (8, 9, PINK, 'Pinky'),
            (10, 9, CYAN, 'Inky'),
            (9, 10, ORANGE, 'Clyde'),
        ]
        self.ghosts = [Ghost(x, y, c, n) for x, y, c, n in ghost_data]

        self.waka_toggle = False
        self.waka_timer = 0
        self.death_timer = 0
        self.respawn_timer = 0
        self.level_complete_timer = 0
        self.level_complete = False
        self.ghost_score_multiplier = 1

    def reset_level(self):
        self.maze = [row[:] for row in MAZE]
        self.pellets_eaten = 0
        self.pacman.reset()
        for ghost in self.ghosts:
            ghost.reset()
        self.ghost_score_multiplier = 1

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()

            if event.type == pygame.KEYDOWN:
                if self.state == 'start':
                    if event.key == pygame.K_SPACE or event.key == pygame.K_RETURN:
                        self.state = 'playing'
                        self.start_sound.play()

                elif self.state == 'playing':
                    if event.key == pygame.K_LEFT or event.key == pygame.K_a:
                        self.pacman.next_direction = (-1, 0)
                    elif event.key == pygame.K_RIGHT or event.key == pygame.K_d:
                        self.pacman.next_direction = (1, 0)
                    elif event.key == pygame.K_UP or event.key == pygame.K_w:
                        self.pacman.next_direction = (0, -1)
                    elif event.key == pygame.K_DOWN or event.key == pygame.K_s:
                        self.pacman.next_direction = (0, 1)
                    elif event.key == pygame.K_p:
                        self.state = 'paused'

                elif self.state == 'paused':
                    if event.key == pygame.K_p or event.key == pygame.K_SPACE:
                        self.state = 'playing'

                elif self.state == 'game_over':
                    if event.key == pygame.K_SPACE or event.key == pygame.K_RETURN:
                        self.score = 0
                        self.lives = 3
                        self.level = 1
                        self.init_game()
                        self.state = 'start'

    def update(self):
        if self.state != 'playing':
            return

        # Update particles
        self.particles = [p for p in self.particles if p.update()]

        # Update score popups
        self.score_popups = [(x, y, s, t - 1) for x, y, s, t in self.score_popups if t > 0]

        # Flash timer
        self.flash_timer += 1
        if self.flash_timer > 15:
            self.flash_timer = 0
            self.flash_on = not self.flash_on

        # Death animation
        if not self.pacman.alive:
            self.pacman.death_anim += 1
            self.death_timer += 1
            if self.death_timer > 60:
                self.lives -= 1
                if self.lives <= 0:
                    self.state = 'game_over'
                    if self.score > self.high_score:
                        self.high_score = self.score
                else:
                    self.pacman.reset()
                    for ghost in self.ghosts:
                        ghost.reset()
                    self.death_timer = 0
                    self.ghost_score_multiplier = 1
            return

        # Level complete
        if self.level_complete:
            self.level_complete_timer += 1
            if self.level_complete_timer > 120:
                self.level += 1
                self.reset_level()
                self.level_complete = False
                self.level_complete_timer = 0
            return

        # Update pacman
        self.pacman.update(self.maze)

        # Check pellet eating
        px, py = self.pacman.x, self.pacman.y
        if 0 <= px < COLS and 0 <= py < ROWS:
            cell = self.maze[py][px]
            if cell == 0:
                self.maze[py][px] = 2
                self.score += 10
                self.pellets_eaten += 1

                # Waka sound
                self.waka_timer += 1
                if self.waka_timer >= 2:
                    self.waka_timer = 0
                    self.waka_sound.play()

                # Particles
                for _ in range(3):
                    wx = px * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
                    wy = py * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
                    self.particles.append(Particle(wx, wy, PELLET_COLOR))

                if self.pellets_eaten >= self.total_pellets:
                    self.level_complete = True
                    self.level_complete_timer = 0

            elif cell == 3:
                self.maze[py][px] = 2
                self.score += 50
                self.pellets_eaten += 1
                self.power_sound.play()
                self.ghost_score_multiplier = 1

                for ghost in self.ghosts:
                    ghost.get_scared()

                # Big particles
                for _ in range(10):
                    wx = px * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
                    wy = py * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
                    self.particles.append(Particle(wx, wy, GOLD))

                if self.pellets_eaten >= self.total_pellets:
                    self.level_complete = True

        # Update ghosts
        for ghost in self.ghosts:
            ghost.update(self.maze, self.pacman.x, self.pacman.y)

            # Check collision
            dist = math.sqrt((ghost.pixel_x - self.pacman.pixel_x) ** 2 +
                             (ghost.pixel_y - self.pacman.pixel_y) ** 2)

            if dist < CELL_SIZE - 4:
                if ghost.scared and not ghost.eyes_only:
                    # Eat ghost
                    ghost.eaten = True
                    ghost.eyes_only = True
                    ghost.scared = False
                    points = 200 * self.ghost_score_multiplier
                    self.ghost_score_multiplier *= 2
                    self.score += points
                    self.eat_ghost_sound.play()

                    # Popup
                    gx = ghost.pixel_x + MAZE_OFFSET_X
                    gy = ghost.pixel_y + MAZE_OFFSET_Y
                    self.score_popups.append((gx, gy, str(points), 60))

                    for _ in range(15):
                        self.particles.append(Particle(gx, gy, ghost.color))

                elif not ghost.scared and not ghost.eyes_only and not ghost.eaten:
                    # Pacman dies
                    self.pacman.alive = False
                    self.death_sound.play()
                    self.death_timer = 0

                    for _ in range(20):
                        wx = self.pacman.pixel_x + MAZE_OFFSET_X
                        wy = self.pacman.pixel_y + MAZE_OFFSET_Y
                        self.particles.append(Particle(wx, wy, YELLOW))

    def draw_maze(self):
        for row in range(ROWS):
            for col in range(COLS):
                cell = self.maze[row][col]
                x = col * CELL_SIZE + MAZE_OFFSET_X
                y = row * CELL_SIZE + MAZE_OFFSET_Y

                if cell == 1:
                    # Wall with gradient effect
                    wall_rect = pygame.Rect(x, y, CELL_SIZE, CELL_SIZE)
                    pygame.draw.rect(self.screen, BLUE, wall_rect)
                    pygame.draw.rect(self.screen, LIGHT_BLUE, wall_rect, 1)

                    # Inner highlight
                    inner = pygame.Rect(x + 2, y + 2, CELL_SIZE - 4, CELL_SIZE - 4)
                    pygame.draw.rect(self.screen, DARK_BLUE, inner)

                elif cell == 0:
                    # Pellet
                    cx = x + CELL_SIZE // 2
                    cy = y + CELL_SIZE // 2
                    pygame.draw.circle(self.screen, PELLET_COLOR, (cx, cy), 3)

                elif cell == 3:
                    # Power pellet with pulsing effect
                    cx = x + CELL_SIZE // 2
                    cy = y + CELL_SIZE // 2
                    pulse = int(math.sin(pygame.time.get_ticks() * 0.005) * 3)
                    r = 7 + pulse
                    pygame.draw.circle(self.screen, GOLD, (cx, cy), r)
                    pygame.draw.circle(self.screen, WHITE, (cx, cy), r - 3)

    def draw_ui(self):
        # Score
        score_text = self.font_small.render(f"SCORE: {self.score}", True, WHITE)
        self.screen.blit(score_text, (20, 20))

        # High score
        hi_text = self.font_small.render(f"HIGH: {self.high_score}", True, GOLD)
        hi_rect = hi_text.get_rect(centerx=SCREEN_WIDTH // 2, y=20)
        self.screen.blit(hi_text, hi_rect)

        # Level
        level_text = self.font_small.render(f"LEVEL: {self.level}", True, CYAN)
        level_rect = level_text.get_rect(right=SCREEN_WIDTH - 20, y=20)
        self.screen.blit(level_text, level_rect)

        # Lives
        for i in range(self.lives):
            lx = 20 + i * 30
            ly = SCREEN_HEIGHT - 35
            # Mini pacman
            pygame.draw.circle(self.screen, YELLOW, (lx + 10, ly + 10), 10)
            pygame.draw.polygon(self.screen, BG_COLOR, [(lx + 10, ly + 10),
                                                        (lx + 20, ly + 5),
                                                        (lx + 20, ly + 15)])

        # Score popups
        for x, y, s, t in self.score_popups:
            alpha = min(255, t * 4)
            popup_text = self.font_small.render(s, True, GOLD)
            popup_text.set_alpha(alpha)
            self.screen.blit(popup_text, (x - popup_text.get_width() // 2, y - (60 - t)))

    def draw_background(self):
        self.screen.fill(BG_COLOR)
        # Stars
        for sx, sy, sr in self.stars:
            brightness = random.randint(150, 255)
            pygame.draw.circle(self.screen, (brightness, brightness, brightness), (sx, sy), sr)

    def draw_start_screen(self):
        self.draw_background()

        # Title
        title = self.font_large.render("PAC-MAN", True, YELLOW)
        title_rect = title.get_rect(centerx=SCREEN_WIDTH // 2, y=150)
        self.screen.blit(title, title_rect)

        # Glow effect
        glow = self.font_large.render("PAC-MAN", True, GOLD)
        glow.set_alpha(100)
        self.screen.blit(glow, (title_rect.x - 2, title_rect.y - 2))

        # Subtitle
        sub = self.font_medium.render("PRESS SPACE TO START", True, WHITE)
        if self.flash_on:
            sub_rect = sub.get_rect(centerx=SCREEN_WIDTH // 2, y=280)
            self.screen.blit(sub, sub_rect)

        # Controls
        controls = [
            "WASD or ARROW KEYS to move",
            "P to pause",
            "Eat power pellets to scare ghosts!",
        ]
        for i, ctrl in enumerate(controls):
            text = self.font_tiny.render(ctrl, True, LIGHT_BLUE)
            rect = text.get_rect(centerx=SCREEN_WIDTH // 2, y=380 + i * 30)
            self.screen.blit(text, rect)

        # Draw demo ghosts
        ghost_colors = [RED, PINK, CYAN, ORANGE]
        ghost_names = ["BLINKY", "PINKY", "INKY", "CLYDE"]
        for i, (color, name) in enumerate(zip(ghost_colors, ghost_names)):
            gx = 150 + i * 130
            gy = 500
            # Ghost body
            pygame.draw.circle(self.screen, color, (gx, gy), 20)
            pygame.draw.rect(self.screen, color, (gx - 20, gy, 40, 20))
            # Eyes
            pygame.draw.circle(self.screen, WHITE, (gx - 7, gy - 5), 6)
            pygame.draw.circle(self.screen, WHITE, (gx + 7, gy - 5), 6)
            pygame.draw.circle(self.screen, DARK_BLUE, (gx - 5, gy - 5), 3)
            pygame.draw.circle(self.screen, DARK_BLUE, (gx + 9, gy - 5), 3)
            name_text = self.font_tiny.render(name, True, color)
            name_rect = name_text.get_rect(centerx=gx, y=gy + 25)
            self.screen.blit(name_text, name_rect)

        if self.high_score > 0:
            hi = self.font_small.render(f"HIGH SCORE: {self.high_score}", True, GOLD)
            hi_rect = hi.get_rect(centerx=SCREEN_WIDTH // 2, y=230)
            self.screen.blit(hi, hi_rect)

    def draw_game_over(self):
        self.draw_background()

        over_text = self.font_large.render("GAME OVER", True, RED)
        over_rect = over_text.get_rect(centerx=SCREEN_WIDTH // 2, y=200)
        self.screen.blit(over_text, over_rect)

        score_text = self.font_medium.render(f"SCORE: {self.score}", True, WHITE)
        score_rect = score_text.get_rect(centerx=SCREEN_WIDTH // 2, y=300)
        self.screen.blit(score_text, score_rect)

        if self.score >= self.high_score and self.score > 0:
            new_hi = self.font_medium.render("NEW HIGH SCORE!", True, GOLD)
            new_hi_rect = new_hi.get_rect(centerx=SCREEN_WIDTH // 2, y=360)
            self.screen.blit(new_hi, new_hi_rect)

        if self.flash_on:
            restart = self.font_small.render("PRESS SPACE TO PLAY AGAIN", True, WHITE)
            restart_rect = restart.get_rect(centerx=SCREEN_WIDTH // 2, y=440)
            self.screen.blit(restart, restart_rect)

    def draw_paused(self):
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 128))
        self.screen.blit(overlay, (0, 0))

        pause_text = self.font_large.render("PAUSED", True, YELLOW)
        pause_rect = pause_text.get_rect(centerx=SCREEN_WIDTH // 2, centery=SCREEN_HEIGHT // 2)
        self.screen.blit(pause_text, pause_rect)

        resume = self.font_small.render("Press P to resume", True, WHITE)
        resume_rect = resume.get_rect(centerx=SCREEN_WIDTH // 2, y=SCREEN_HEIGHT // 2 + 60)
        self.screen.blit(resume, resume_rect)

    def draw_level_complete(self):
        if self.flash_on:
            text = self.font_large.render(f"LEVEL {self.level} CLEAR!", True, GOLD)
            rect = text.get_rect(centerx=SCREEN_WIDTH // 2, centery=SCREEN_HEIGHT // 2)
            self.screen.blit(text, rect)

    def draw(self):
        if self.state == 'start':
            self.draw_start_screen()
        elif self.state == 'game_over':
            self.draw_game_over()
        else:
            self.draw_background()
            self.draw_maze()

            # Draw ghosts
            for ghost in self.ghosts:
                ghost.draw(self.screen, MAZE_OFFSET_X, MAZE_OFFSET_Y)

            # Draw pacman
            self.pacman.draw(self.screen, MAZE_OFFSET_X, MAZE_OFFSET_Y)

            # Draw particles
            for particle in self.particles:
                particle.draw(self.screen)

            self.draw_ui()

            if self.state == 'paused':
                self.draw_paused()

            if self.level_complete:
                self.draw_level_complete()

        pygame.display.flip()

    def run(self):
        print("Starting PAC-MAN game...")
        print("Controls: WASD or Arrow Keys to move, P to pause")

        while True:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(60)


if __name__ == "__main__":
    game = Game()
    game.run()